index 9a16ca96db76..4a9e686da1ec 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -929,6 +929,22 @@ Instruction *InstCombinerImpl::foldAddWithConstant(BinaryOperator &Add) {
   if (match(Op0, m_ZExt(m_Xor(m_Value(X), m_APInt(C2)))) &&
       C2->isMinSignedValue() && C2->sext(Ty->getScalarSizeInBits()) == *C)
     return CastInst::Create(Instruction::SExt, X, Ty);
+  // Is this add the last step in a convoluted sext with nneg zext?
+  // add(zext nneg (add nsw X, C1), C2) --> add(sext X, C1 + C2)
+  // The nneg flag on zext implies the add result is non-negative.
+  // The nsw flag on the inner add ensures signed overflow is undefined,
+  // making the transformation valid.
+  const APInt *C1;
+  if (match(Op0, m_NNegZExt(m_NSWAdd(m_Value(X), m_APInt(C1))))) {
+    // Special case: when constants cancel out (C1 + C2 = 0), result is just sext X
+    if (C1->sext(Ty->getScalarSizeInBits()) == -*C)
+      return CastInst::Create(Instruction::SExt, X, Ty);
+    // General case: add(zext nneg (add nsw X, C1), C2) -> add(sext X, C1 + C2)
+    Value *SextX = Builder.CreateSExt(X, Ty);
+    Constant *WideC1 = ConstantInt::get(Ty, C1->sext(Ty->getScalarSizeInBits()));
+    Constant *NewC = ConstantExpr::getAdd(WideC1, Op1C);
+    return BinaryOperator::CreateAdd(SextX, NewC);
+  }

